/**
 * 云端渲染数字人
 */
export declare class CloudAvatar extends RtcAvatar {
    private _avatarVideoEle?;
    private _innerVideoEle;
    private _chromaKeyProcessor;
    private _alphaMaskProcessor;
    private _stutterMonitor;
    /** ClientMotionData 中 batch_id 递增，与每段 1s 的 MotionData 对齐 */
    private _clientMotionBatchSeq;
    constructor(avatarConfig: IAvatarInitConfig);
    private _init;
    exit(): void;
    private _setupRTCView;
    /**
     * 移动端 Safari：非用户手势下对「有声」video.play() 会 NotAllowedError；抠像后音轨在输出流上，可先静音起播再恢复。
     */
    private _safePlayAvatarVideo;
    start(dialogParams: IDialogConfig): Promise<void>;
    /**
     * 将外部传入的 int16 PCM（与 .pcm 文件内容一致）按 1s 切段，封装为 JBIN MotionData，
     * 再按 format.md（同目录）约定分片后经 dataChannel 发送。
     * @param audio 一段连续 PCM（单个 {@link Int16Array}），或多段分片（{@link Int16Array[]} 再拼接）
     * @param end 是否为当前流最后一包（用于 end_of_batch）
     */
    pushAudioData(audio: Int16Array | Int16Array[], end?: boolean): void;
    /**
     * 将一整块 MotionData 二进制切条后经 RTC dataChannel 发送：
     * 先发首包（总长、片数），再按序发 Base64 片（与 format.md 一致）。
     * 切条宽度见 {@link DEFAULT_CLIENT_MOTION_SLICE_BYTES}。
     */
    private _sendClientMotionDataChunked;
    private _videoSubscribeStateChangedHandler;
    /**
     * 远端推流视频透明背景处理
     * @returns void
     */
    private _remoteTransparentBackgroundProcessor;
}

